use std::collections::BTreeMap;
use std::error::Error;

use super::r_selection::{self, AvailableCandidate, VersionRequirement};
use super::rig_client::{self, AvailableR};

// Generated by build.rs from src/rig/r-versions.json:
// - EMBEDDED_AVAILABLE_BUILD_DATE: &str
// - EMBEDDED_AVAILABLE: &[AvailableCandidate<'static>]
include!(concat!(env!("OUT_DIR"), "/r_version_releases.rs"));

const MINOR_RELEASE_FLOOR: (u64, u64) = (4, 1);

pub(crate) fn latest_minor_version_on(exclude_newer: &str) -> Result<String, Box<dyn Error>> {
    let (major, minor) = if exclude_newer <= EMBEDDED_AVAILABLE_BUILD_DATE {
        latest_minor_version_from_candidates(exclude_newer, EMBEDDED_AVAILABLE.iter().copied())?
    } else {
        let available = all_available()?;
        latest_minor_version_from_candidates(
            exclude_newer,
            available.iter().map(AvailableCandidate::from),
        )?
    };

    Ok(format!("{major}.{minor}"))
}

pub(crate) fn required_available_version(
    req: &str,
    requirement: &VersionRequirement,
    exclude_newer: Option<&str>,
) -> Result<AvailableR, Box<dyn Error>> {
    if let Some(exclude_newer) = exclude_newer {
        if exclude_newer <= EMBEDDED_AVAILABLE_BUILD_DATE {
            return required_available_version_from_candidates(
                req,
                requirement,
                Some(exclude_newer),
                EMBEDDED_AVAILABLE.iter().copied(),
            );
        }

        let available = all_available()?;
        return required_available_version_from_candidates(
            req,
            requirement,
            Some(exclude_newer),
            available.iter().map(AvailableCandidate::from),
        );
    }

    let available = rig_client::available()?;
    required_available_version_from_candidates(
        req,
        requirement,
        None,
        available.iter().map(AvailableCandidate::from),
    )
}

fn latest_minor_version_from_candidates<'a>(
    exclude_newer: &str,
    candidates: impl IntoIterator<Item = AvailableCandidate<'a>>,
) -> Result<(u64, u64), Box<dyn Error>> {
    let mut first_release_dates = BTreeMap::new();
    for candidate in candidates {
        let Some((major, minor, _patch)) = version_parts(candidate.version) else {
            continue;
        };
        if (major, minor) < MINOR_RELEASE_FLOOR {
            continue;
        }
        let Some(date) = candidate.date.and_then(r_selection::iso_date_prefix) else {
            continue;
        };
        first_release_dates
            .entry((major, minor))
            .and_modify(|previous: &mut &str| {
                if date < *previous {
                    *previous = date;
                }
            })
            .or_insert(date);
    }

    first_release_dates
        .into_iter()
        .filter(|(_, date)| *date <= exclude_newer)
        .map(|(version, _)| version)
        .max()
        .ok_or_else(|| {
            format!(
                "could not resolve latest R minor version available before or on {exclude_newer}"
            )
            .into()
        })
}

fn required_available_version_from_candidates<'a>(
    req: &str,
    requirement: &VersionRequirement,
    exclude_newer: Option<&str>,
    candidates: impl IntoIterator<Item = AvailableCandidate<'a>>,
) -> Result<AvailableR, Box<dyn Error>> {
    r_selection::select_available_candidate(req, requirement, exclude_newer, candidates)
        .map(AvailableR::from)
}

fn all_available() -> Result<Vec<AvailableR>, Box<dyn Error>> {
    let json = String::from_utf8(rig_client::output(&["available", "--all", "--json"])?)
        .map_err(|e| format!("`rig available --all --json` returned non-UTF-8 output: {e}"))?;
    parse_available_json(&json, "rig available --all --json")
}

fn parse_available_json(json: &str, command: &str) -> Result<Vec<AvailableR>, Box<dyn Error>> {
    let mut versions: Vec<AvailableR> =
        serde_json::from_str(json).map_err(|e| format!("failed to parse `{command}` JSON: {e}"))?;

    for version in &mut versions {
        if let Some(date) = version.date.as_deref() {
            version.date = Some(
                r_selection::iso_date_prefix(date)
                    .ok_or_else(|| {
                        format!(
                            "rig available returned invalid release date `{}` for R {}",
                            date, version.version
                        )
                    })?
                    .to_string(),
            );
        }
    }

    Ok(versions)
}

fn version_parts(value: &str) -> Option<(u64, u64, u64)> {
    let mut parts = value.split('.');
    let major = parts.next()?.parse().ok()?;
    let minor = parts.next()?.parse().ok()?;
    let patch = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }
    Some((major, minor, patch))
}

impl<'a> From<&'a AvailableR> for AvailableCandidate<'a> {
    fn from(value: &'a AvailableR) -> Self {
        Self {
            name: &value.name,
            version: &value.version,
            date: value.date.as_deref(),
        }
    }
}

impl From<AvailableCandidate<'_>> for AvailableR {
    fn from(value: AvailableCandidate<'_>) -> Self {
        Self {
            name: value.name.to_string(),
            version: value.version.to_string(),
            date: value.date.map(str::to_string),
        }
    }
}
